import React, { useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

export default function Home() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [offices, setOffices] = useState([]);
  const [myTokens, setMyTokens] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [offRes, tokRes] = await Promise.all([
          api.get('/offices'),
          api.get('/tokens/my'),
        ]);
        setOffices(offRes.data);
        setMyTokens(tokRes.data.filter((t) => ['waiting', 'serving'].includes(t.status)));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);

  if (loading) return <div className="loading">Loading...</div>;

  const activeToken = myTokens[0];

  return (
    <div className="app-shell">
      <div className="screen">
        {/* Top bar */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
          <div>
            <p style={{ color: '#5A8A93', fontSize: 11 }}>Good day,</p>
            <h2 style={{ marginTop: 2 }}>{user?.name}</h2>
          </div>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <div
              style={{ width: 36, height: 36, borderRadius: '50%', background: '#02C39A', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#0A2E36', fontWeight: 700, fontSize: 13 }}
            >
              {user?.name?.[0]?.toUpperCase()}
            </div>
            <button onClick={logout} style={{ background: 'none', border: 'none', color: '#5A8A93', fontSize: 12, cursor: 'pointer' }}>Logout</button>
          </div>
        </div>

        {/* Active token card */}
        {activeToken && (
          <>
            <p className="section-label">Your active token</p>
            <div
              onClick={() => navigate(`/token/${activeToken._id}`)}
              style={{ background: '#028090', borderRadius: 18, padding: 18, marginBottom: 16, cursor: 'pointer', position: 'relative', overflow: 'hidden' }}
            >
              <div style={{ position: 'absolute', right: -20, top: -20, width: 90, height: 90, borderRadius: '50%', background: 'rgba(2,195,154,0.2)' }} />
              <p style={{ color: 'rgba(255,255,255,0.65)', fontSize: 10, letterSpacing: 1, textTransform: 'uppercase', marginBottom: 4 }}>Token number</p>
              <p style={{ color: '#fff', fontSize: 44, fontWeight: 700, fontFamily: 'monospace', lineHeight: 1 }}>
                {String(activeToken.tokenNumber).padStart(3, '0')}
              </p>
              <p style={{ color: 'rgba(255,255,255,0.8)', fontSize: 11, marginTop: 6 }}>{activeToken.office?.name}</p>
              <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                <div style={{ background: 'rgba(0,0,0,0.25)', borderRadius: 8, padding: '5px 10px', color: '#fff', fontSize: 11, flex: 1, textAlign: 'center' }}>
                  <span style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: 9 }}>Ahead of you</span>
                  {activeToken.peopleAhead} people
                </div>
                <div style={{ background: 'rgba(0,0,0,0.25)', borderRadius: 8, padding: '5px 10px', color: '#fff', fontSize: 11, flex: 1, textAlign: 'center' }}>
                  <span style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: 9 }}>Est. wait</span>
                  ~{activeToken.estimatedWait} min
                </div>
                <div style={{ background: 'rgba(0,0,0,0.25)', borderRadius: 8, padding: '5px 10px', color: '#02C39A', fontSize: 11, flex: 1, textAlign: 'center', fontWeight: 600 }}>
                  <span style={{ display: 'block', color: 'rgba(255,255,255,0.6)', fontSize: 9, fontWeight: 400 }}>Status</span>
                  {activeToken.status === 'serving' ? 'YOUR TURN!' : 'Waiting'}
                </div>
              </div>
            </div>
          </>
        )}

        {/* Offices list */}
        <p className="section-label">Nearby offices</p>
        {offices.map((office) => (
          <div key={office._id} className="card" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <h3>{office.name}</h3>
              <p style={{ color: '#5A8A93', fontSize: 11, marginTop: 3 }}>{office.address}</p>
              <p style={{ color: '#5A8A93', fontSize: 11, marginTop: 2 }}>
                Now serving: <span style={{ color: '#02C39A', fontWeight: 600 }}>#{office.currentToken}</span>
              </p>
            </div>
            <div style={{ textAlign: 'right', flexShrink: 0, marginLeft: 12 }}>
              <p style={{ color: '#02C39A', fontSize: 16, fontWeight: 700 }}>
                {Math.max(0, office.lastToken - office.currentToken)} in queue
              </p>
              <p style={{ color: '#5A8A93', fontSize: 10, marginTop: 2 }}>
                ~{Math.max(0, office.lastToken - office.currentToken) * 5} min wait
              </p>
              <button
                className="btn-primary"
                style={{ marginTop: 8, padding: '6px 14px', fontSize: 11, width: 'auto', borderRadius: 8 }}
                onClick={() => navigate(`/book/${office._id}`)}
              >
                Book →
              </button>
            </div>
          </div>
        ))}

        {offices.length === 0 && (
          <div style={{ textAlign: 'center', color: '#5A8A93', marginTop: 40 }}>
            <p>No offices found.</p>
            <button
              className="btn-secondary"
              style={{ marginTop: 12, width: 'auto', padding: '8px 20px' }}
              onClick={() => api.post('/offices/seed/demo').then(() => window.location.reload())}
            >
              Load demo offices
            </button>
          </div>
        )}

        {/* Bottom nav */}
        <nav className="bottom-nav">
          <Link to="/" className="bnav-item active">
            <svg width="20" height="20" viewBox="0 0 20 20" fill="none"><rect x="2" y="9" width="7" height="9" rx="1.5" fill="white"/><rect x="11" y="4" width="7" height="14" rx="1.5" fill="white" opacity=".5"/></svg>
            <span className="bnav-label">Home</span>
          </Link>
          <Link to={activeToken ? `/token/${activeToken._id}` : '/'} className="bnav-item">
            <svg width="20" height="20" viewBox="0 0 20 20" fill="none"><rect x="4" y="2" width="12" height="16" rx="2" stroke="white" strokeWidth="1.5"/><path d="M7 7h6M7 10h4" stroke="white" strokeWidth="1.2" strokeLinecap="round"/></svg>
            <span className="bnav-label">My Token</span>
          </Link>
        </nav>
      </div>
    </div>
  );
}
